}

// ─── Request Row ─────────────────────────────────────────────────────────────
function RequestRow({ req, onAction, onEdit, isManager, userRole }) {
  const [acting, setActing] = useState('');
  const name    = req.LeaveType?.LeaveTypeName || req.leaveType?.LeaveTypeName || req.leaveTypeName || req.LeaveTypeName || req.type || '—';
  const from    = (req.StartDate || req.startDate) ? new Date(req.StartDate || req.startDate).toLocaleDateString() : '—';
  const to      = (req.EndDate   || req.endDate)   ? new Date(req.EndDate   || req.endDate).toLocaleDateString()   : '—';
  const days    = req.TotalDays ?? req.totalDays ?? req.numberOfDays ?? req.days ?? '—';
  const status  = req.Status || req.status || 'SUBMITTED';
  const id      = req.LeaveRequestID || req.leaveRequestId || req.id;
  const empName = req.Employee?.FullName || req.employee?.FullName || req.employeeName
                || [req.employee?.firstName, req.employee?.lastName].filter(Boolean).join(' ') || '—';

  const act = async (action) => {
    setActing(action);
    try { await onAction(id, action); } finally { setActing(''); }
  };

  const isFinal      = isFinalStatus(status);
  const isCancellable = !isFinal;
  const displayLabel = STATUS_LABEL[status] || status;

  const statusStyle = {
    display: 'inline-block', padding: '3px 10px', borderRadius: 20,
    fontSize: '0.75rem', fontWeight: 600,
    background: normStatus(status) === 'APPROVED' ? 'rgba(34,197,94,0.15)'
              : normStatus(status) === 'REJECTED'  ? 'rgba(239,68,68,0.15)'
              : normStatus(status) === 'CANCELLED' ? 'rgba(156,163,175,0.15)'
              : 'rgba(251,191,36,0.15)',
    color:      normStatus(status) === 'APPROVED' ? '#16a34a'
              : normStatus(status) === 'REJECTED'  ? '#dc2626'
              : normStatus(status) === 'CANCELLED' ? '#6b7280'
              : '#b45309',
  };

  return (
    <tr>
      <td>
        <div style={{ fontWeight: 500 }}>{name}</div>
        {(req.Reason || req.reason) && (
          <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', marginTop: 2 }}>
            {(req.Reason || req.reason).slice(0, 50)}…
          </div>
        )}
        {(req.DocumentReference || req.documentReference) && (
          <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)', marginTop: 2, display: 'flex', alignItems: 'center', gap: 3 }}>
            <FileText size={11} />{req.DocumentReference || req.documentReference}
          </div>
        )}
      </td>
      {isManager && <td><div style={{ fontWeight: 500 }}>{empName}</div></td>}
      <td style={{ fontSize: '0.82rem' }}>{from} → {to}</td>
      <td>{days !== '—' ? `${days} day${days !== 1 ? 's' : ''}` : '—'}{req.IsHalfDay || req.isHalfDay ? ' (½)' : ''}</td>
      <td><span style={statusStyle}>{displayLabel}</span></td>
      {isManager && (
        <td style={{ fontSize: '0.78rem', color: 'var(--text-secondary)', maxWidth: 160 }}>
          {(req.Reason || req.reason || '—').slice(0, 60)}{(req.Reason || req.reason || '').length > 60 ? '…' : ''}
        </td>
      )}
      <td>
        <div style={{ display: 'flex', gap: 6 }}>
          {isManager && !isFinal && (
            <>
              <button className="btn btn-success btn-sm" onClick={() => act('approve')} disabled={!!acting}>
                {acting === 'approve' ? <InlineSpinner /> : <><Check size={13} /> Approve</>}
              </button>
              <button className="btn btn-danger btn-sm" onClick={() => act('reject')} disabled={!!acting}>
                {acting === 'reject' ? <InlineSpinner /> : <><X size={13} /> Reject</>}
              </button>
            </>
          )}
          {!isManager && isCancellable && (
            <>
              <button className="btn btn-ghost btn-sm" onClick={() => onEdit(req)}>
                <Edit3 size={14} /> Edit
              </button>
              <button className="btn btn-ghost btn-sm" onClick={() => act('cancel')} disabled={!!acting}>
                {acting === 'cancel' ? <InlineSpinner /> : 'Cancel'}
              </button>
            </>
          )}
        </div>
      </td>
    </tr>
  );
}

// ─── Submit Leave Form (LV-015, LV-016, LV-031) ──────────────────────────────
function SubmitLeaveForm({ leaveTypes, onSubmit, loading }) {
  const [form, setForm] = useState({
    LeaveTypeID: '', startDate: '', endDate: '', reason: '',
    isHalfDay: false, documentReference: '', attachmentFile: null,
    isPostSubmission: false,
  });
  const [errors, setErrors] = useState({});
  const set = (k, v) => { setForm(f => ({ ...f, [k]: v })); setErrors(e => ({ ...e, [k]: '' })); };

  const validate = () => {
    const e = {};
    if (!form.LeaveTypeID) e.LeaveTypeID = 'Select a leave type';
    if (!form.startDate)   e.startDate   = 'Required';
    if (!form.endDate)     e.endDate     = 'Required';
    if (form.startDate && form.endDate && form.endDate < form.startDate)
      e.endDate = 'End date must be after start date';
    return e;
  };

  const handle = () => {
    const e = validate();
    if (Object.keys(e).length) { setErrors(e); return; }
    onSubmit({
      LeaveTypeID:         parseInt(form.LeaveTypeID, 10),
      StartDate:           form.startDate,
      EndDate:             form.endDate,
      IsHalfDay:           form.isHalfDay,
      Reason:              form.reason || null,
      DocumentReference:   form.documentReference || null,
      IsPostSubmission:    form.isPostSubmission,
      AttachmentFile:      form.attachmentFile,
    });
  };

  const days = form.startDate && form.endDate
    ? Math.max(0, Math.round((new Date(form.endDate) - new Date(form.startDate)) / 86400000) + 1)
    : 0;

  const today = new Date().toISOString().split('T')[0];

  return (
    <>
      {/* Progress steps */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 4, marginBottom: 20 }}>
        {[{ l: 'Leave Type', done: !!form.LeaveTypeID }, { l: 'Dates', done: !!(form.startDate && form.endDate) }, { l: 'Details', done: false }]
          .map((s, i, arr) => (
            <React.Fragment key={i}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 5, fontSize: '0.75rem', color: s.done ? '#16a34a' : 'var(--text-secondary)', fontWeight: s.done ? 600 : 400 }}>
                <span style={{ width: 18, height: 18, borderRadius: '50%', display: 'inline-flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.6rem', fontWeight: 700, background: s.done ? 'rgba(34,197,94,0.15)' : 'var(--surface-alt,#2a2a3a)', color: s.done ? '#16a34a' : 'var(--text-muted)', border: '1px solid', borderColor: s.done ? 'rgba(34,197,94,0.4)' : 'var(--border)' }}>
                  {s.done ? '✓' : i + 1}
                </span>
                {s.l}
              </div>
              {i < arr.length - 1 && <span style={{ flex: 1, height: 1, background: 'var(--border)', margin: '0 4px' }} />}
            </React.Fragment>
          ))}
      </div>

      <div className="form-group">
        <label className="form-label required">Leave Type</label>
        <select className="form-select" value={form.LeaveTypeID} onChange={e => set('LeaveTypeID', e.target.value)}>
          <option value="">— Select a leave type —</option>
          {leaveTypes.map(t => {
            const id   = t.leaveTypeId  || t.LeaveTypeID  || t.id;
            const name = t.leaveTypeName || t.LeaveTypeName || t.name;
            return <option key={id} value={id}>{name}</option>;
          })}
        </select>
        {errors.LeaveTypeID && <div className="form-error">{errors.LeaveTypeID}</div>}
      </div>

      <div className="form-row">
        <div className="form-group">
          <label className="form-label required">Start Date</label>
          <input className="form-input" type="date" value={form.startDate}
            onChange={e => set('startDate', e.target.value)} />
          {errors.startDate && <div className="form-error">{errors.startDate}</div>}
        </div>
        <div className="form-group">
          <label className="form-label required">End Date</label>
          <input className="form-input" type="date" value={form.endDate}
            min={form.startDate || undefined}
            onChange={e => set('endDate', e.target.value)} />
          {errors.endDate && <div className="form-error">{errors.endDate}</div>}
        </div>
      </div>

      {/* LV-031 — post-leave submission toggle */}
      {form.startDate && form.startDate < today && (
        <div style={{ padding: '10px 14px', background: 'rgba(251,191,36,0.08)', border: '1px solid rgba(251,191,36,0.3)', borderRadius: 'var(--radius-md)', marginBottom: 14, fontSize: '0.83rem', color: '#b45309' }}>
          <label style={{ display: 'flex', alignItems: 'center', gap: 8, cursor: 'pointer' }}>
            <input type="checkbox" checked={form.isPostSubmission} onChange={e => set('isPostSubmission', e.target.checked)} />
            <span><strong>Post-Leave Submission</strong> — Start date is in the past. Check this if submitting after the leave occurred.</span>
          </label>
        </div>
      )}

      {days > 0 && (
        <div style={{ padding: '10px 14px', background: 'rgba(34,197,94,0.07)', border: '1px solid rgba(34,197,94,0.2)', borderRadius: 'var(--radius-md)', marginBottom: 14, fontSize: '0.85rem', color: '#16a34a', fontWeight: 500 }}>
          📅 <strong>{days} calendar day{days !== 1 ? 's' : ''}</strong>
          <span style={{ opacity: 0.7, marginLeft: 6, fontWeight: 400 }}>(net working days confirmed on submit)</span>
        </div>
      )}

      <div className="form-group">
        <label style={{ display: 'flex', alignItems: 'center', gap: 8, cursor: 'pointer', fontSize: '0.875rem', userSelect: 'none' }}>
          <input type="checkbox" checked={form.isHalfDay} onChange={e => set('isHalfDay', e.target.checked)} />
          <span>Half-day <span style={{ color: 'var(--text-secondary)', fontSize: '0.78rem' }}>(0.5 days deducted)</span></span>
        </label>
