      </div>

      {/* LV-016 — Attach documents */}
      <div className="form-group">
        <label className="form-label">
          Document Reference
          <span style={{ color: 'var(--text-secondary)', fontSize: '0.76rem', fontWeight: 400, marginLeft: 6 }}>required for sick &gt;1 day · maternity · bereavement</span>
        </label>
        <input className="form-input" type="text" value={form.documentReference}
          onChange={e => set('documentReference', e.target.value)}
          placeholder="Medical cert no., birth cert ref., death cert no. …" />
      </div>

      <div className="form-group">
        <label className="form-label">
          Attach File <span style={{ color: 'var(--text-secondary)', fontSize: '0.76rem', fontWeight: 400, marginLeft: 6 }}>PDF / image</span>
        </label>
        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          <label style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '7px 14px', background: 'var(--surface)', border: '1px solid var(--border)', borderRadius: 'var(--radius-md)', cursor: 'pointer', fontSize: '0.83rem', color: 'var(--text-secondary)' }}>
            <Upload size={14} />
            {form.attachmentFile ? form.attachmentFile.name : 'Choose file…'}
            <input type="file" accept=".pdf,image/*" style={{ display: 'none' }}
              onChange={e => set('attachmentFile', e.target.files[0] || null)} />
          </label>
          {form.attachmentFile && (
            <button onClick={() => set('attachmentFile', null)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--red)' }}><X size={14} /></button>
          )}
        </div>
      </div>

      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: 16, paddingTop: 14, borderTop: '1px solid var(--border-light)' }}>
        <button className="btn btn-ghost" type="button" disabled={loading}
          onClick={() => { setForm({ LeaveTypeID: '', startDate: '', endDate: '', reason: '', isHalfDay: false, documentReference: '', attachmentFile: null, isPostSubmission: false }); setErrors({}); }}>
          Clear form
        </button>
        <button className="btn btn-primary" onClick={handle}
          disabled={loading || !form.LeaveTypeID || !form.startDate || !form.endDate}>
          {loading ? <InlineSpinner /> : <><Send size={15} style={{ marginRight: 6 }} />Submit Request</>}
        </button>
      </div>
    </>
  );
}

