// ─── Team Leave Calendar (LV-035, LV-036) ────────────────────────────────────
function TeamLeaveCalendar({ teamLeaves }) {
  const today = new Date();
  const [month, setMonth] = useState(today.getMonth());
  const [year,  setYear]  = useState(today.getFullYear());
  const [filterEmp, setFilterEmp] = useState('');

  const firstDay = new Date(year, month, 1).getDay();
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const monthName = new Date(year, month).toLocaleString('default', { month: 'long', year: 'numeric' });

  const filtered = teamLeaves.filter(l => !filterEmp || (l.employeeName || '').toLowerCase().includes(filterEmp.toLowerCase()));

  const leavesOnDay = (day) => {
    const d = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    return filtered.filter(l => {
      const start = (l.StartDate || l.startDate || '').split('T')[0];
      const end   = (l.EndDate   || l.endDate   || '').split('T')[0];
      return d >= start && d <= end && !isFinalStatus(l.Status || l.status) === false;
    });
  };

  const cells = [...Array(firstDay).fill(null), ...Array.from({ length: daysInMonth }, (_, i) => i + 1)];
  const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899'];

  return (
    <div className="card">
      <div className="card-header">
        <div className="card-title">Team Leave Calendar</div>
        <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
          <input className="form-input" type="text" placeholder="Filter by employee…" value={filterEmp}
            onChange={e => setFilterEmp(e.target.value)} style={{ width: 180, padding: '5px 10px', fontSize: '0.82rem' }} />
          <button className="btn btn-ghost btn-sm" onClick={() => { if (month === 0) { setMonth(11); setYear(y => y - 1); } else setMonth(m => m - 1); }}>‹</button>
          <span style={{ fontWeight: 600, whiteSpace: 'nowrap', fontSize: '0.9rem' }}>{monthName}</span>
          <button className="btn btn-ghost btn-sm" onClick={() => { if (month === 11) { setMonth(0); setYear(y => y + 1); } else setMonth(m => m + 1); }}>›</button>
        </div>
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: 2, marginBottom: 4 }}>
        {['Sun','Mon','Tue','Wed','Thu','Fri','Sat'].map(d => (
          <div key={d} style={{ textAlign: 'center', fontSize: '0.72rem', fontWeight: 600, color: 'var(--text-muted)', padding: '4px 0', textTransform: 'uppercase' }}>{d}</div>
        ))}
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: 2 }}>
        {cells.map((day, i) => {
          if (!day) return <div key={`e-${i}`} />;
          const leaves = leavesOnDay(day);
          const isToday = day === today.getDate() && month === today.getMonth() && year === today.getFullYear();
          return (
            <div key={day} style={{ minHeight: 64, background: isToday ? 'rgba(59,130,246,0.1)' : 'var(--surface)', borderRadius: 'var(--radius-sm)', padding: 4, border: isToday ? '1px solid rgba(59,130,246,0.4)' : '1px solid var(--border-light)' }}>
              <div style={{ fontSize: '0.75rem', fontWeight: isToday ? 700 : 400, color: isToday ? 'var(--blue)' : 'var(--text-secondary)', marginBottom: 2 }}>{day}</div>
              {leaves.slice(0, 2).map((l, li) => (
                <div key={li} title={l.employeeName || l.Employee?.FullName} style={{ fontSize: '0.65rem', background: COLORS[li % COLORS.length] + '33', color: COLORS[li % COLORS.length], borderRadius: 3, padding: '1px 4px', marginBottom: 1, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                  {l.employeeName || l.Employee?.FullName || 'Leave'}
                </div>
              ))}
              {leaves.length > 2 && <div style={{ fontSize: '0.6rem', color: 'var(--text-muted)' }}>+{leaves.length - 2} more</div>}
            </div>
          );
        })}
      </div>
    </div>
  );
}
// ── Update Leave Request (LV-017) ────────────────────────────────────────────
async function updateLeaveRequest(leaveRequestId, data, updatedById) {
  const request = await prisma.leaveRequest.findUnique({
    where: { LeaveRequestID: leaveRequestId },
    include: { LeaveType: true, Employee: true },
  });

  if (!request) throw new AppError('Leave request not found.', 404, 'NOT_FOUND');

  // Cannot modify final states
  if (isFinalStatus(request.Status)) {
    throw new AppError(`Cannot modify request with status '${request.Status}'.`, 400, 'INVALID_STATUS');
  }

  // Validate date changes don't create overlaps
  if (data.StartDate || data.EndDate) {
    const startDate = data.StartDate || request.StartDate;
    const endDate = data.EndDate || request.EndDate;

    const overlapping = await prisma.leaveRequest.findFirst({
      where: {
        EmployeeID: request.EmployeeID,
        LeaveRequestID: { not: leaveRequestId },
        Status: { in: [LEAVE_REQUEST_STATUS.SUBMITTED, LEAVE_REQUEST_STATUS.PENDING_MANAGER, LEAVE_REQUEST_STATUS.APPROVED] },
        AND: [
          { StartDate: { lte: new Date(endDate) } },
          { EndDate: { gte: new Date(startDate) } },
        ],
      },
    });

    if (overlapping) {
      throw new AppError(`Overlapping ${overlapping.Status} request exists.`, 409, 'LEAVE_OVERLAP');
    }
  }

  // Recalculate days if dates changed
  let totalDays = request.TotalDays;
  if (data.StartDate || data.EndDate || data.IsHalfDay) {
    const holidays = await getHolidayDatesInRange(
      request.EmployeeID,
      data.StartDate || request.StartDate,
      data.EndDate || request.EndDate
    );
    totalDays = data.IsHalfDay ?? request.IsHalfDay 
      ? 0.5 
      : countEgyptianBusinessDays(
          data.StartDate || request.StartDate,
          data.EndDate || request.EndDate,
          holidays
        );
  }

  return prisma.$transaction(async (tx) => {
    // Update request
    const updated = await tx.leaveRequest.update({
      where: { LeaveRequestID: leaveRequestId },
      data: {
        StartDate: data.StartDate ? new Date(data.StartDate) : undefined,
        EndDate: data.EndDate ? new Date(data.EndDate) : undefined,
        Reason: data.Reason,
        DocumentReference: data.DocumentReference,
        LeaveTypeID: data.LeaveTypeID,
        TotalDays: totalDays,
        IsHalfDay: data.IsHalfDay,
        UpdatedAt: new Date(),
      },
      include: { LeaveType: true },
    });

    // If already approved, adjust balance
    if (request.Status === LEAVE_REQUEST_STATUS.APPROVED) {
      const balance = await tx.leaveBalance.findFirst({
        where: {
          EmployeeID: request.EmployeeID,
          LeaveTypeID: request.LeaveTypeID,
          BalanceYear: dayjs(request.StartDate).year(),
        },
      });

      if (balance) {
        const dayDiff = Number(totalDays) - Number(request.TotalDays);
        await tx.leaveBalance.update({
          where: { LeaveBalanceID: balance.LeaveBalanceID },
          data: {
            UsedDays: { increment: dayDiff },
            LastUpdatedAt: new Date(),
          },
        });
      }
    }

    // Audit log
    await tx.leaveActionLog.create({
      data: {
        LeaveRequestID: leaveRequestId,
        ActionBy: updatedById,
        ActionType: LEAVE_ACTION_TYPE.MODIFIED,
        PreviousStatus: request.Status,
        NewStatus: request.Status,
        Notes: `Modified by ${updatedById}: ${JSON.stringify(data)}`,
      },
    });

    return updated;
  });
}
// ─── Leave Pattern Alerts (LV-037–040) ───────────────────────────────────────
function LeavePatternAlerts({ requests }) {
  // Detect employees with frequent short leaves (Monday/Friday pattern, excessive sick days)
  const patterns = React.useMemo(() => {
    const byEmp = {};
    requests.forEach(r => {
      const emp = r.employeeName || r.Employee?.FullName || r.employee?.FullName || 'Unknown';
      if (!byEmp[emp]) byEmp[emp] = [];
      byEmp[emp].push(r);
    });

    const flags = [];
    Object.entries(byEmp).forEach(([name, reqs]) => {
      const sickCount = reqs.filter(r => (r.leaveTypeName || r.LeaveTypeName || '').toLowerCase().includes('sick')).length;
      if (sickCount >= 3) flags.push({ employee: name, type: 'Excessive Sick Days', count: sickCount, severity: 'high' });

      const monFri = reqs.filter(r => {
        const d = new Date(r.StartDate || r.startDate);
        return d.getDay() === 1 || d.getDay() === 5;
      }).length;
      if (monFri >= 3 && reqs.length >= 3) flags.push({ employee: name, type: 'Mon/Fri Pattern', count: monFri, severity: 'medium' });
    });
    return flags;
  }, [requests]);

  if (patterns.length === 0) return (
    <div className="card">
      <div className="card-header"><div className="card-title"><TrendingUp size={16} style={{ marginRight: 6 }} />Leave Pattern Analysis</div></div>
      <div style={{ textAlign: 'center', padding: 24, color: 'var(--text-muted)', fontSize: '0.85rem' }}>No irregular patterns detected</div>
    </div>
  );

  return (
    <div className="card">
      <div className="card-header">
        <div className="card-title"><AlertTriangle size={16} style={{ marginRight: 6, color: 'var(--gold)' }} />Leave Pattern Alerts</div>
        <span className="badge badge-pending">{patterns.length}</span>
      </div>
      {patterns.map((p, i) => (
        <div key={i} style={{ padding: '12px 0', borderBottom: '1px solid var(--border-light)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <div style={{ fontWeight: 600, fontSize: '0.875rem' }}>{p.employee}</div>
            <div style={{ fontSize: '0.77rem', color: 'var(--text-secondary)', marginTop: 2 }}>{p.type} — {p.count} occurrences</div>
          </div>
          <span style={{ padding: '3px 10px', borderRadius: 20, fontSize: '0.72rem', fontWeight: 700, background: p.severity === 'high' ? 'rgba(239,68,68,0.15)' : 'rgba(251,191,36,0.15)', color: p.severity === 'high' ? '#dc2626' : '#b45309' }}>
            {p.severity === 'high' ? 'High' : 'Medium'}
          </span>
        </div>
      ))}
    </div>
  );
}

