            <div className="card p-4">
              <h4 className="mb-3"><ArrowRightLeft size={16} /> Balance Adjustments</h4>
              <button className="btn-sm btn-outline" onClick={() => handleAdjustBalance({})}>Perform Manual Adjustment</button>
            </div>
          </div>
        )}
      </div>

      {actionLoading && (
        <div className="loading-overlay">
          <InlineSpinner label="Processing system workflow..." />
        </div>
      )}
    </div>
  );
}
